fixed_code:
fn main() {
    let arr = [1, 2, 3, 4];
    let window_size = 5;

    if let Some(w) = arr.windows(window_size).next() {
        println!("{:?}", w);
    } else {
        eprintln!("Window size larger than array length");
    }
}

